+        reg.register(p2, sample_content("second parent"));
+
+        reg.set_parent(child, p1);
+        assert_eq!(reg.resolve(child).unwrap().short, "first parent");
+
+        // Reparent
+        reg.set_parent(child, p2);
+        assert_eq!(reg.resolve(child).unwrap().short, "second parent");
+    }
